import{c as a,Q as o,j as t,m as i}from"./chunks/framework.Bj0Eefkv.js";const p=JSON.parse('{"title":"Desbravador KDS — Requisitos de Hardware e Infraestrutura","description":"","frontmatter":{},"headers":[],"relativePath":"perifericos/kds-desbravador.md","filePath":"perifericos/kds-desbravador.md","lastUpdated":1784161795000}'),r={name:"perifericos/kds-desbravador.md"};function s(d,e,n,l,c,u){return o(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="desbravador-kds-—-requisitos-de-hardware-e-infraestrutura" tabindex="-1">Desbravador KDS — Requisitos de Hardware e Infraestrutura <a class="header-anchor" href="#desbravador-kds-—-requisitos-de-hardware-e-infraestrutura" aria-label="Permalink to &quot;Desbravador KDS — Requisitos de Hardware e Infraestrutura&quot;">​</a></h1><p><strong>Sistema:</strong> Desbravador KDS (Kitchen Display System) — Integrado ao PDV<br><strong>Integra com:</strong> POS Fast by Desbravador · Desbravador Enterprise / 4.0<br><strong>Público:</strong> Cliente / Equipe de TI / Fornecedor de hardware</p><hr><h2 id="historico-de-revisoes" tabindex="-1">Histórico de Revisões <a class="header-anchor" href="#historico-de-revisoes" aria-label="Permalink to &quot;Histórico de Revisões&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Versão</th><th>Data</th><th>Descrição</th><th>Responsável</th></tr></thead><tbody><tr><td>1.0</td><td>Jul/2026</td><td>Criação do documento</td><td>Desbravador Software Ltda.</td></tr></tbody></table><hr><blockquote><p>ℹ️ Esta é uma página compartilhada entre os sistemas Desbravador que integram com o módulo KDS.</p></blockquote><h2 id="_1-objetivo" tabindex="-1">1. Objetivo <a class="header-anchor" href="#_1-objetivo" aria-label="Permalink to &quot;1. Objetivo&quot;">​</a></h2><p>Este documento apresenta os requisitos técnicos recomendados para instalação e utilização do sistema KDS — Kitchen Display System — integrado ao PDV.</p><p>O KDS permite que pedidos realizados no PDV sejam enviados e visualizados em monitores instalados nos diferentes setores da cozinha, como cozinha quente, cozinha fria, bar, confeitaria, expedição ou demais áreas operacionais.</p><hr><h2 id="_2-arquitetura-de-funcionamento" tabindex="-1">2. Arquitetura de Funcionamento <a class="header-anchor" href="#_2-arquitetura-de-funcionamento" aria-label="Permalink to &quot;2. Arquitetura de Funcionamento&quot;">​</a></h2><p>O sistema utiliza uma arquitetura centralizada, composta por:</p><ul><li>Uma máquina principal com sistema operacional Windows.</li><li>Serviço local executado por meio do ambiente XAMPP.</li><li>Comunicação com o sistema de PDV.</li><li>Monitores, tablets, computadores ou Smart TVs acessando o KDS por navegador.</li><li>Rede local conectando todos os dispositivos.</li></ul><p>A máquina principal funciona como servidor do KDS.</p><p>Os demais dispositivos da cozinha não precisam instalar o sistema. O acesso é realizado por meio de um navegador Google Chrome, utilizando o endereço de rede disponibilizado pelo servidor.</p><hr><h2 id="_3-requisitos-da-maquina-principal-—-servidor-kds" tabindex="-1">3. Requisitos da Máquina Principal — Servidor KDS <a class="header-anchor" href="#_3-requisitos-da-maquina-principal-—-servidor-kds" aria-label="Permalink to &quot;3. Requisitos da Máquina Principal — Servidor KDS&quot;">​</a></h2><p>A máquina principal será responsável por executar:</p><ul><li>Sistema operacional Windows.</li><li>Ambiente XAMPP.</li><li>Aplicação do KDS.</li><li>Comunicação com o PDV.</li><li>Disponibilização do sistema para os demais monitores da cozinha.</li></ul><h3 id="_3-1-requisitos-minimos" tabindex="-1">3.1 Requisitos mínimos <a class="header-anchor" href="#_3-1-requisitos-minimos" aria-label="Permalink to &quot;3.1 Requisitos mínimos&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Campo</th><th>Especificação</th></tr></thead><tbody><tr><td><strong>Sistema Operacional</strong></td><td>Windows 10 ou superior</td></tr><tr><td><strong>Processador</strong></td><td>Intel Core i3, AMD Ryzen 3 ou equivalente</td></tr><tr><td><strong>Memória RAM</strong></td><td>8 GB</td></tr><tr><td><strong>Armazenamento disponível</strong></td><td>20 GB (preferencialmente SSD)</td></tr><tr><td><strong>Rede</strong></td><td>Placa Ethernet ou Wi-Fi</td></tr><tr><td><strong>Navegador</strong></td><td>Google Chrome atualizado</td></tr><tr><td><strong>Periféricos</strong></td><td>Mouse e teclado para instalação, configuração e manutenção</td></tr><tr><td><strong>Endereço IP</strong></td><td>Fixo ou reserva de IP configurada na rede local</td></tr><tr><td><strong>XAMPP</strong></td><td>Instalado e configurado</td></tr></tbody></table><h3 id="_3-2-configuracao-recomendada" tabindex="-1">3.2 Configuração recomendada <a class="header-anchor" href="#_3-2-configuracao-recomendada" aria-label="Permalink to &quot;3.2 Configuração recomendada&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Campo</th><th>Especificação</th></tr></thead><tbody><tr><td><strong>Sistema Operacional</strong></td><td>Windows 11 Pro</td></tr><tr><td><strong>Processador</strong></td><td>Intel Core i5, AMD Ryzen 5 ou superior</td></tr><tr><td><strong>Memória RAM</strong></td><td>16 GB</td></tr><tr><td><strong>Armazenamento</strong></td><td>SSD com pelo menos 50 GB disponíveis</td></tr><tr><td><strong>Rede</strong></td><td>Conexão cabeada</td></tr><tr><td><strong>Proteção Elétrica</strong></td><td>Nobreak para proteção contra oscilações e quedas de energia</td></tr><tr><td><strong>Inicialização</strong></td><td>Automática dos serviços do KDS e do XAMPP</td></tr></tbody></table><h3 id="_3-3-observacoes" tabindex="-1">3.3 Observações <a class="header-anchor" href="#_3-3-observacoes" aria-label="Permalink to &quot;3.3 Observações&quot;">​</a></h3><p>A máquina principal deve permanecer ligada durante todo o período de operação do estabelecimento.</p><blockquote><p>⚠️ Caso o servidor seja desligado, desconectado da rede ou apresente falha, os demais dispositivos poderão perder temporariamente o acesso ao KDS.</p></blockquote><p>Recomenda-se que a máquina utilizada como servidor não seja compartilhada com aplicações que consumam muitos recursos de processamento ou memória.</p><hr><h2 id="_4-requisitos-dos-monitores-de-cozinha" tabindex="-1">4. Requisitos dos Monitores de Cozinha <a class="header-anchor" href="#_4-requisitos-dos-monitores-de-cozinha" aria-label="Permalink to &quot;4. Requisitos dos Monitores de Cozinha&quot;">​</a></h2><p>Os monitores de cozinha acessam o KDS por navegador e não necessitam de instalação local da aplicação.</p><p>Podem ser utilizados:</p><ul><li>Computadores Windows.</li><li>Mini PCs.</li><li>Notebooks.</li><li>Tablets.</li><li>Monitores com computador acoplado.</li><li>Smart TVs com sistema Android TV.</li></ul><h3 id="_4-1-requisitos-gerais" tabindex="-1">4.1 Requisitos gerais <a class="header-anchor" href="#_4-1-requisitos-gerais" aria-label="Permalink to &quot;4.1 Requisitos gerais&quot;">​</a></h3><p>O dispositivo deve possuir:</p><ul><li>Acesso à mesma rede local do servidor KDS.</li><li>Navegador Google Chrome atualizado.</li><li>Tela com resolução mínima de 1280 × 720.</li><li>Resolução recomendada de 1920 × 1080 — Full HD.</li><li>Conexão de rede estável.</li><li>Capacidade de manter o navegador aberto durante toda a operação.</li><li>Fonte de energia permanente durante o uso.</li></ul><hr><h2 id="_5-utilizacao-em-computadores-windows" tabindex="-1">5. Utilização em Computadores Windows <a class="header-anchor" href="#_5-utilizacao-em-computadores-windows" aria-label="Permalink to &quot;5. Utilização em Computadores Windows&quot;">​</a></h2><p>Para utilização em computadores Windows, recomenda-se:</p><table tabindex="0"><thead><tr><th>Campo</th><th>Especificação</th></tr></thead><tbody><tr><td><strong>Sistema Operacional</strong></td><td>Windows 10 ou superior</td></tr><tr><td><strong>Memória RAM</strong></td><td>Mínimo 4 GB</td></tr><tr><td><strong>Navegador</strong></td><td>Google Chrome atualizado</td></tr><tr><td><strong>Periféricos</strong></td><td>Mouse e teclado para configuração inicial e manutenção</td></tr><tr><td><strong>Tela</strong></td><td>Pelo menos 15 polegadas</td></tr><tr><td><strong>Rede</strong></td><td>Cabeada ou Wi-Fi estável</td></tr></tbody></table><p>O uso de mouse e teclado facilita a operação, a atualização da página, a autenticação e eventuais configurações do dispositivo.</p><hr><h2 id="_6-utilizacao-em-tablets" tabindex="-1">6. Utilização em Tablets <a class="header-anchor" href="#_6-utilizacao-em-tablets" aria-label="Permalink to &quot;6. Utilização em Tablets&quot;">​</a></h2><p>O KDS pode ser acessado por tablets por meio do Google Chrome.</p><table tabindex="0"><thead><tr><th>Campo</th><th>Especificação</th></tr></thead><tbody><tr><td><strong>Sistema Operacional</strong></td><td>Android atualizado</td></tr><tr><td><strong>Tela</strong></td><td>Mínimo 10 polegadas</td></tr><tr><td><strong>Memória RAM</strong></td><td>Mínimo 4 GB</td></tr><tr><td><strong>Navegador</strong></td><td>Google Chrome atualizado</td></tr><tr><td><strong>Rede</strong></td><td>Wi-Fi estável</td></tr><tr><td><strong>Suporte</strong></td><td>Estrutura de fixação apropriada</td></tr><tr><td><strong>Energia</strong></td><td>Alimentação elétrica contínua</td></tr></tbody></table><blockquote><p>ℹ️ Para ambientes de cozinha, recomenda-se a utilização de capa protetora e suporte adequado contra umidade, gordura, calor e impactos.</p></blockquote><hr><h2 id="_7-utilizacao-em-smart-tvs" tabindex="-1">7. Utilização em Smart TVs <a class="header-anchor" href="#_7-utilizacao-em-smart-tvs" aria-label="Permalink to &quot;7. Utilização em Smart TVs&quot;">​</a></h2><p>O sistema também pode funcionar em Smart TVs, desde que o equipamento utilize o sistema operacional Android TV.</p><h3 id="requisitos-obrigatorios" tabindex="-1">Requisitos obrigatórios <a class="header-anchor" href="#requisitos-obrigatorios" aria-label="Permalink to &quot;Requisitos obrigatórios&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Campo</th><th>Especificação</th></tr></thead><tbody><tr><td><strong>Sistema Operacional</strong></td><td>Android TV</td></tr><tr><td><strong>Navegador</strong></td><td>Google Chrome instalado ou navegador compatível com aplicações web modernas</td></tr><tr><td><strong>Periférico</strong></td><td>Mouse USB ou Bluetooth conectado</td></tr><tr><td><strong>Rede</strong></td><td>Mesma rede local do servidor KDS</td></tr><tr><td><strong>Resolução</strong></td><td>Mínima HD, preferencialmente Full HD</td></tr><tr><td><strong>Operação</strong></td><td>Capacidade de manter o navegador aberto durante a operação</td></tr></tbody></table><h3 id="restricoes" tabindex="-1">Restrições <a class="header-anchor" href="#restricoes" aria-label="Permalink to &quot;Restrições&quot;">​</a></h3><p>Não é garantido o funcionamento em Smart TVs que utilizem sistemas operacionais proprietários, como:</p><ul><li>Samsung Tizen.</li><li>LG webOS.</li><li>Roku TV.</li><li>Sistemas sem suporte ao Google Chrome.</li><li>Equipamentos que não permitam conexão de mouse.</li></ul><blockquote><p>⚠️ <strong>Atenção</strong> — Mesmo em dispositivos Android TV, deve ser realizada uma validação prévia do modelo do equipamento, pois alguns fabricantes podem limitar a instalação ou a execução do navegador.</p></blockquote><hr><h2 id="_8-requisitos-de-rede" tabindex="-1">8. Requisitos de Rede <a class="header-anchor" href="#_8-requisitos-de-rede" aria-label="Permalink to &quot;8. Requisitos de Rede&quot;">​</a></h2><p>Todos os dispositivos do KDS devem estar conectados à mesma rede local da máquina principal.</p><h3 id="requisitos-minimos" tabindex="-1">Requisitos mínimos <a class="header-anchor" href="#requisitos-minimos" aria-label="Permalink to &quot;Requisitos mínimos&quot;">​</a></h3><ul><li>Rede Ethernet ou Wi-Fi.</li><li>Comunicação liberada entre o servidor e os dispositivos.</li><li>Endereço IP fixo ou reservado para a máquina principal.</li><li>Ausência de bloqueios de firewall entre os equipamentos.</li><li>Sinal Wi-Fi estável nos setores da cozinha.</li><li>Roteador ou infraestrutura de rede compatível com a quantidade de dispositivos.</li></ul><h3 id="recomendacao" tabindex="-1">Recomendação <a class="header-anchor" href="#recomendacao" aria-label="Permalink to &quot;Recomendação&quot;">​</a></h3><p>Sempre que possível, a máquina principal e os dispositivos fixos devem utilizar conexão cabeada.</p><p>A conexão Wi-Fi pode ser utilizada em tablets ou locais onde não seja possível instalar cabeamento, desde que haja boa cobertura e estabilidade de sinal.</p><hr><h2 id="_9-acesso-ao-sistema" tabindex="-1">9. Acesso ao Sistema <a class="header-anchor" href="#_9-acesso-ao-sistema" aria-label="Permalink to &quot;9. Acesso ao Sistema&quot;">​</a></h2><p>O acesso ao KDS será realizado por meio de endereço de rede informado durante a implantação.</p><p>Exemplo:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>http://192.168.0.100/kds</span></span></code></pre></div><p>O endereço poderá variar conforme a configuração da rede do cliente.</p><blockquote><p>ℹ️ Recomenda-se criar um atalho do KDS na área de trabalho ou configurar o navegador para abrir automaticamente o sistema ao iniciar o dispositivo.</p></blockquote><hr><h2 id="_10-recomendacoes-operacionais" tabindex="-1">10. Recomendações Operacionais <a class="header-anchor" href="#_10-recomendacoes-operacionais" aria-label="Permalink to &quot;10. Recomendações Operacionais&quot;">​</a></h2><p>Para garantir maior disponibilidade do KDS, recomenda-se:</p><ul><li>Manter a máquina principal sempre ligada.</li><li>Configurar o XAMPP para iniciar automaticamente com o Windows.</li><li>Configurar o navegador dos monitores para abrir o KDS automaticamente.</li><li>Desabilitar suspensão automática e hibernação.</li><li>Desabilitar protetor de tela durante a operação.</li><li>Evitar atualizações automáticas do Windows durante o horário de funcionamento.</li><li>Utilizar endereço IP fixo no servidor.</li><li>Utilizar nobreak na máquina principal e nos equipamentos de rede.</li><li>Manter o Google Chrome atualizado.</li><li>Monitorar a qualidade da rede local.</li><li>Restringir o uso dos dispositivos do KDS para outras finalidades.</li></ul><hr><h2 id="_11-responsabilidades-do-cliente" tabindex="-1">11. Responsabilidades do Cliente <a class="header-anchor" href="#_11-responsabilidades-do-cliente" aria-label="Permalink to &quot;11. Responsabilidades do Cliente&quot;">​</a></h2><p>São de responsabilidade do cliente:</p><ul><li>Disponibilizar os equipamentos dentro dos requisitos indicados.</li><li>Disponibilizar licenças válidas do sistema operacional.</li><li>Disponibilizar rede local estável.</li><li>Providenciar cabeamento, Wi-Fi e pontos de energia.</li><li>Disponibilizar mouse e teclado quando necessários.</li><li>Garantir que Smart TVs utilizem Android TV.</li><li>Manter os equipamentos protegidos contra calor, umidade, gordura e impactos.</li><li>Garantir acesso administrativo à máquina Windows durante a implantação.</li><li>Disponibilizar profissional de TI quando forem necessárias configurações de rede ou firewall.</li></ul><blockquote><p>⚠️ <strong>Atenção</strong> — A Desbravador <strong>NÃO</strong> realiza montagem/desmontagem de hardware nem instalação de sistemas operacionais.</p></blockquote><hr><h2 id="_12-consideracoes-finais" tabindex="-1">12. Considerações Finais <a class="header-anchor" href="#_12-consideracoes-finais" aria-label="Permalink to &quot;12. Considerações Finais&quot;">​</a></h2><p>O desempenho e a disponibilidade do KDS dependem diretamente da qualidade da máquina principal, dos dispositivos de exibição e da infraestrutura de rede local.</p><p>A utilização de equipamentos abaixo dos requisitos mínimos, redes instáveis ou Smart TVs com sistemas não compatíveis poderá comprometer o funcionamento da solução.</p><blockquote><p>ℹ️ Antes da implantação, recomenda-se realizar uma validação técnica do ambiente, especialmente quando forem utilizadas Smart TVs, tablets ou equipamentos compartilhados com outros sistemas.</p></blockquote><p>O documento separa requisitos mínimos, recomendados, rede, servidor, tablets e Smart TVs, deixando claro que Android TV é obrigatório nesse cenário.</p><hr><h2 id="_13-contato-e-suporte" tabindex="-1">13. Contato e Suporte <a class="header-anchor" href="#_13-contato-e-suporte" aria-label="Permalink to &quot;13. Contato e Suporte&quot;">​</a></h2><p><strong>Desbravador Software Ltda.</strong><br> 🌐 <a href="https://www.desbravador.com.br" target="_blank" rel="noreferrer">www.desbravador.com.br</a></p><p>Para dúvidas técnicas durante a implantação, a equipe Desbravador estará disponível para esclarecimentos.</p>',89)])])}const h=a(r,[["render",s]]);export{p as __pageData,h as default};
